import {HashRouter, Routes, Route} from "react-router-dom";
import {Link} from "react-router-dom";
import Mylogin from "./login";
import Myregister from "./register";

const UserModule = () => {
  
  return (
    <HashRouter>     
          <section className="bg-light p-3">
            <div className="container-fluid">
                <div className="row">
                    <div className="col-lg-6">
                        <h2> User Management System</h2> 
                    </div>

                    <div className="col-lg-6 text-end">
                    <Link className=" btn btn-primary text-white m-1" to="/register" ><i className='fa fa-user-plus'></i> Create Account</Link>
                  
                    <Link className="btn btn-primary text-white m-1" to="/login"> <i className='fa fa-lock'></i> Login</Link>
                    
                </div>
            </div>
            </div>
        </section>
     <Routes>  
       <Route exact path="/login" element={<Mylogin />} />
     <Route exact path="/register" element={<Myregister />} />
     </Routes>
   </HashRouter> 
  
  );
};

export default UserModule;
